class AuthBackend(ABC):
    """Common interface for in-memory authentication backends."""

    backend_type = "auth"

    def __init__(self, name: str, enabled: bool = True, default_ttl: float = 3600.0) -> None:
        if not name:
            raise VaultError("auth backend name is required")
        self.name = name
        self.enabled = enabled
        self.default_ttl = default_ttl

    @abstractmethod
    def authenticate(self, **credentials: Any) -> AuthenticationResult:
