class UserpassAuthBackend(AuthBackend):
    """Username/password authentication with salted password hashing."""

    backend_type = "userpass"

    def __init__(
        self,
        name: str = "userpass",
        enabled: bool = True,
        default_ttl: float = 3600.0,
        iterations: int = 200_000,
    ) -> None:
        super().__init__(name=name, enabled=enabled, default_ttl=default_ttl)
        if iterations <= 0:
            raise VaultError("password hash iterations must be positive")
        self.iterations = iterations
        self._users: dict[str, UserpassAccount] = {}

    def create_user(
        self,
        username: str,
        password: str,
        policies: list[str] | None = None,
        metadata: dict[str, str] | None = None,
        ttl: float | None = None,
        disabled: bool = False,
    ) -> UserpassAccount:
        if not username:
            raise VaultError("username is required")
        if not password:
            raise VaultError("password is required")
        if username in self._users:
            raise VaultError(f"user already exists: {username}")

        salt = generate_salt(16)
        account = UserpassAccount(
            username=username,
            password_hash=self._hash_password(password, salt),
            salt=salt,
            policies=list(policies or []),
            metadata=dict(metadata or {}),
            ttl=self.default_ttl if ttl is None else ttl,
            disabled=disabled,
        )
        self._users[username] = account
        return account

    def set_password(self, username: str, password: str) -> None:
        account = self._users.get(username)
        if account is None:
            raise VaultError(f"user not found: {username}")
        if not password:
            raise VaultError("password is required")
        salt = generate_salt(16)
        account.salt = salt
        account.password_hash = self._hash_password(password, salt)
        account.updated_at = time.time()

    def get_user(self, username: str) -> UserpassAccount | None:
        return self._users.get(username)

    def delete_user(self, username: str) -> bool:
        return self._users.pop(username, None) is not None

    def enable_user(self, username: str) -> None:
        account = self._require_user(username)
        account.disabled = False
        account.updated_at = time.time()

    def disable_user(self, username: str) -> None:
        account = self._require_user(username)
        account.disabled = True
        account.updated_at = time.time()

    def list_users(self) -> list[str]:
        return sorted(self._users.keys())

    def authenticate(self, **credentials: Any) -> AuthenticationResult:
        self._ensure_enabled()
        username = str(_required(credentials, "username", "user"))
        password = str(_required(credentials, "password"))

        account = self._users.get(username)
        if account is None or account.disabled:
            raise AuthenticationError("invalid username or password")

        candidate = self._hash_password(password, account.salt)
        if not constant_time_compare(candidate, account.password_hash):
            raise AuthenticationError("invalid username or password")

        return AuthenticationResult(
            backend=self.name,
            subject=username,
            policies=list(account.policies),
            metadata=dict(account.metadata),
            ttl=account.ttl,
        )

    def _require_user(self, username: str) -> UserpassAccount:
        account = self._users.get(username)
        if account is None:
            raise VaultError(f"user not found: {username}")
        return account

    def _hash_password(self, password: str, salt: bytes) -> bytes:
        return hashlib.pbkdf2_hmac("sha256", password.encode(), salt, self.iterations)


@dataclass
class AppRoleSecretID:
    """A generated AppRole secret ID."""

    secret_id: str
    role_name: str
    metadata: dict[str, str] = field(default_factory=dict)
    ttl: float = 0.0
    num_uses: int = 0
    uses_remaining: int = 0
    created_at: float = field(default_factory=time.time)

    def __post_init__(self) -> None:
        if self.num_uses > 0 and self.uses_remaining == 0:
            self.uses_remaining = self.num_uses

    def is_expired(self, now: float | None = None) -> bool:
        return self.ttl > 0 and _now(now) >= self.created_at + self.ttl

    def can_use(self, now: float | None = None) -> bool:
        if self.is_expired(now):
            return False
        return not (self.num_uses > 0 and self.uses_remaining <= 0)

    def use(self, now: float | None = None) -> None:
        if not self.can_use(now):
            raise AuthenticationError("invalid role_id or secret_id")
        if self.num_uses > 0:
            self.uses_remaining -= 1

    def to_dict(self) -> dict[str, Any]:
        return {
            "role_name": self.role_name,
            "metadata": dict(self.metadata),
            "ttl": self.ttl,
            "num_uses": self.num_uses,
            "uses_remaining": self.uses_remaining,
            "created_at": self.created_at,
        }


