class AppRoleAuthBackend(AuthBackend):
    """AppRole authentication with generated role IDs and secret IDs."""

    backend_type = "approle"

    def __init__(self, name: str = "approle", enabled: bool = True) -> None:
        super().__init__(name=name, enabled=enabled)
        self._roles: dict[str, AppRoleRole] = {}
        self._role_id_index: dict[str, str] = {}

    def create_role(
        self,
        name: str,
        policies: list[str] | None = None,
        metadata: dict[str, str] | None = None,
        token_ttl: float = 3600.0,
        role_id: str | None = None,
        disabled: bool = False,
    ) -> AppRoleRole:
        if not name:
            raise VaultError("role name is required")
        if name in self._roles:
            raise VaultError(f"approle already exists: {name}")
        rid = role_id or generate_id("role", 24)
        if rid in self._role_id_index:
            raise VaultError("role_id already exists")

        role = AppRoleRole(
            name=name,
            role_id=rid,
            policies=list(policies or []),
            metadata=dict(metadata or {}),
            token_ttl=token_ttl,
            disabled=disabled,
        )
        self._roles[name] = role
        self._role_id_index[rid] = name
        return role

    def get_role(self, name: str) -> AppRoleRole | None:
        return self._roles.get(name)

    def delete_role(self, name: str) -> bool:
        role = self._roles.pop(name, None)
        if role is None:
            return False
        self._role_id_index.pop(role.role_id, None)
        return True

    def list_roles(self) -> list[str]:
        return sorted(self._roles.keys())

    def enable_role(self, name: str) -> None:
        role = self._require_role(name)
        role.disabled = False

    def disable_role(self, name: str) -> None:
        role = self._require_role(name)
        role.disabled = True

    def generate_secret_id(
        self,
        role_name: str,
        metadata: dict[str, str] | None = None,
        ttl: float = 0.0,
        num_uses: int = 0,
        now: float | None = None,
    ) -> AppRoleSecretID:
        role = self._require_role(role_name)
        secret = AppRoleSecretID(
            secret_id=generate_token(24),
            role_name=role_name,
            metadata=dict(metadata or {}),
            ttl=ttl,
            num_uses=num_uses,
            created_at=_now(now),
        )
        role.secret_ids[secret.secret_id] = secret
        return secret

    def revoke_secret_id(self, role_name: str, secret_id: str) -> bool:
        role = self._roles.get(role_name)
        if role is None:
            return False
        return role.secret_ids.pop(secret_id, None) is not None

    def list_secret_ids(self, role_name: str) -> list[str]:
        role = self._require_role(role_name)
        return sorted(role.secret_ids.keys())

    def authenticate(self, **credentials: Any) -> AuthenticationResult:
        self._ensure_enabled()
        role_id = str(_required(credentials, "role_id"))
        secret_id = str(_required(credentials, "secret_id"))
        now = credentials.get("now")

        role_name = self._role_id_index.get(role_id)
        role = self._roles.get(role_name or "")
        if role is None or role.disabled:
            raise AuthenticationError("invalid role_id or secret_id")

        secret = role.secret_ids.get(secret_id)
        if secret is None:
            raise AuthenticationError("invalid role_id or secret_id")
        secret.use(now if isinstance(now, int | float) else None)

        metadata = dict(role.metadata)
        metadata.update(secret.metadata)
        metadata.setdefault("role_name", role.name)
        metadata.setdefault("role_id", role.role_id)
        return AuthenticationResult(
            backend=self.name,
            subject=role.name,
            policies=list(role.policies),
            metadata=metadata,
            ttl=role.token_ttl,
        )

    def _require_role(self, name: str) -> AppRoleRole:
        role = self._roles.get(name)
        if role is None:
            raise VaultError(f"approle not found: {name}")
        return role


