class CertificateAuthBackend(AuthBackend):
    """Certificate fingerprint authentication."""

    backend_type = "cert"

    def __init__(self, name: str = "cert", enabled: bool = True) -> None:
        super().__init__(name=name, enabled=enabled)
        self._certificates: dict[str, CertificateIdentity] = {}
        self._name_index: dict[str, str] = {}

    def add_certificate(
        self,
        name: str,
        fingerprint: str,
        policies: list[str] | None = None,
        metadata: dict[str, str] | None = None,
        ttl: float = 3600.0,
        disabled: bool = False,
    ) -> CertificateIdentity:
        if not name:
            raise VaultError("certificate name is required")
        normalized = self._normalize_fingerprint(fingerprint)
        if not normalized:
            raise VaultError("certificate fingerprint is required")
        if name in self._name_index:
            raise VaultError(f"certificate already exists: {name}")
        if normalized in self._certificates:
            raise VaultError("certificate fingerprint already exists")

        identity = CertificateIdentity(
            name=name,
            fingerprint=normalized,
            policies=list(policies or []),
            metadata=dict(metadata or {}),
            ttl=ttl,
            disabled=disabled,
        )
        self._certificates[normalized] = identity
        self._name_index[name] = normalized
        return identity

    def get_certificate(self, name: str) -> CertificateIdentity | None:
        fingerprint = self._name_index.get(name)
        if fingerprint is None:
            return None
        return self._certificates.get(fingerprint)

    def delete_certificate(self, name: str) -> bool:
        fingerprint = self._name_index.pop(name, None)
        if fingerprint is None:
            return False
        self._certificates.pop(fingerprint, None)
        return True

    def list_certificates(self) -> list[str]:
        return sorted(self._name_index.keys())

    def list_fingerprints(self) -> list[str]:
        return sorted(self._certificates.keys())

    def authenticate(self, **credentials: Any) -> AuthenticationResult:
        self._ensure_enabled()
        fingerprint = credentials.get("fingerprint") or credentials.get("cert_fingerprint")
        certificate = credentials.get("certificate")
        if fingerprint in (None, "") and certificate not in (None, ""):
            fingerprint = self._fingerprint_certificate(certificate)
        if fingerprint in (None, ""):
            raise AuthenticationError("missing authentication input: fingerprint")

        candidate = self._normalize_fingerprint(str(fingerprint))
        identity = self._find_identity(candidate)
        if identity is None or identity.disabled:
            raise AuthenticationError("invalid certificate fingerprint")

        metadata = dict(identity.metadata)
        metadata.setdefault("fingerprint", identity.fingerprint)
        return AuthenticationResult(
            backend=self.name,
            subject=identity.name,
            policies=list(identity.policies),
            metadata=metadata,
            ttl=identity.ttl,
        )

    def _find_identity(self, candidate: str) -> CertificateIdentity | None:
        candidate_bytes = candidate.encode()
        for fingerprint, identity in self._certificates.items():
            if constant_time_compare(candidate_bytes, fingerprint.encode()):
                return identity
        return None

    @staticmethod
    def _normalize_fingerprint(fingerprint: str) -> str:
        return fingerprint.replace(":", "").replace(" ", "").lower()

    @staticmethod
    def _fingerprint_certificate(certificate: Any) -> str:
        if isinstance(certificate, bytes):
            raw = certificate
        else:
            raw = str(certificate).encode()
        return hashlib.sha256(raw).hexdigest()


class TokenAuthBackend(AuthBackend):
    """Authenticate by validating an already-issued token."""

    backend_type = "token"

    def __init__(
        self,
        token_store: TokenStore,
        name: str = "token",
        enabled: bool = True,
    ) -> None:
