        return AuthenticationResult(
            backend=self.name,
            subject=subject,
            policies=list(token.policies),
            metadata=metadata,
            ttl=token.remaining_ttl,
            entity_id=token.entity_id,
            token_id=token.token_id,
            accessor=token.accessor,
            renewable=token.renewable,
        )


class AuthManager:
    """Registry and dispatcher for authentication backends."""

    def __init__(self, backends: list[AuthBackend] | None = None) -> None:
        self._backends: dict[str, AuthBackend] = {}
