class AuthAttemptState:
    """Rate-limit state for one subject."""

    attempts: int = 0
    first_attempt_at: float = 0.0
    last_attempt_at: float = 0.0
    locked_until: float = 0.0

    def to_dict(self) -> dict[str, float | int]:
