class AuthRateLimiter:
    """Deterministic in-memory limiter for authentication attempts."""

    def __init__(
        self,
        max_attempts: int = 5,
        window: float = 60.0,
        lockout_duration: float = 300.0,
    ) -> None:
        if max_attempts <= 0:
            raise VaultError("max_attempts must be positive")
        self.max_attempts = max_attempts
        self.window = window
        self.lockout_duration = lockout_duration
        self._states: dict[str, AuthAttemptState] = {}

    def is_limited(self, subject: str, now: float | None = None) -> bool:
        state = self._states.get(subject)
        return bool(state and state.locked_until > _now(now))

    def check(self, subject: str, now: float | None = None) -> None:
        if self.is_limited(subject, now):
            raise AuthenticationError("authentication rate limit exceeded")

    def record_attempt(
        self,
        subject: str,
        success: bool,
        now: float | None = None,
    ) -> AuthAttemptState:
        current = _now(now)
        if success:
            self._states.pop(subject, None)
            return AuthAttemptState()

        state = self._states.get(subject)
        if state is None or current - state.first_attempt_at > self.window:
            state = AuthAttemptState(first_attempt_at=current)
            self._states[subject] = state

        state.attempts += 1
        state.last_attempt_at = current
        if state.attempts >= self.max_attempts:
            state.locked_until = current + self.lockout_duration
        return state

    def reset(self, subject: str) -> None:
        self._states.pop(subject, None)

    def get_state(self, subject: str) -> AuthAttemptState | None:
        return self._states.get(subject)

    def list_subjects(self) -> list[str]:
        return sorted(self._states.keys())


