            "backend": self.backend,
            "policies": list(self.policies),
            "metadata": dict(self.metadata),
            "created_at": self.created_at,
            "expires_at": self.expires_at,
            "last_seen_at": self.last_seen_at,
            "revoked": self.revoked,
        }


class AuthSessionStore:
    """In-memory authenticated session tracking."""

    def __init__(self) -> None:
        self._sessions: dict[str, AuthSession] = {}

    def create_session(
        self,
        result: AuthenticationResult,
        ttl: float | None = None,
        now: float | None = None,
    ) -> AuthSession:
        current = _now(now)
        session_ttl = result.ttl if ttl is None else ttl
        expires_at = 0.0 if session_ttl <= 0 else current + session_ttl
        session = AuthSession(
            session_id=generate_id("sess", 24),
            subject=result.subject,
            backend=result.backend,
            policies=list(result.policies),
            metadata=dict(result.metadata),
            created_at=current,
            expires_at=expires_at,
            last_seen_at=current,
        )
        self._sessions[session.session_id] = session
        return session

    def get_session(self, session_id: str, now: float | None = None) -> AuthSession | None:
        session = self._sessions.get(session_id)
        if session is None or not session.is_active(now):
            return None
        return session

    def touch_session(self, session_id: str, now: float | None = None) -> bool:
        session = self.get_session(session_id, now)
        if session is None:
            return False
        session.last_seen_at = _now(now)
        return True

    def revoke_session(self, session_id: str) -> bool:
        session = self._sessions.get(session_id)
        if session is None:
            return False
        session.revoked = True
        return True

    def list_sessions(self, subject: str | None = None, active_only: bool = True) -> list[str]:
        sessions = self._sessions.values()
        if subject is not None:
            sessions = [session for session in sessions if session.subject == subject]
        if active_only:
            sessions = [session for session in sessions if session.is_active()]
        return sorted(session.session_id for session in sessions)

    def tidy(self, now: float | None = None) -> int:
        to_remove = [
            session_id
            for session_id, session in self._sessions.items()
            if not session.is_active(now)
        ]
        for session_id in to_remove:
            self._sessions.pop(session_id, None)
        return len(to_remove)


@dataclass
class MFAChallenge:
    """Simple one-time MFA challenge."""

    challenge_id: str
    subject: str
    method: str
    code: str
    created_at: float
    expires_at: float
    metadata: dict[str, str] = field(default_factory=dict)
    verified: bool = False
    attempts: int = 0

    def is_expired(self, now: float | None = None) -> bool:
        return _now(now) >= self.expires_at

    def to_dict(self) -> dict[str, Any]:
        return {
            "challenge_id": self.challenge_id,
            "subject": self.subject,
            "method": self.method,
            "created_at": self.created_at,
            "expires_at": self.expires_at,
            "metadata": dict(self.metadata),
            "verified": self.verified,
            "attempts": self.attempts,
        }


class MFAChallengeStore:
    """In-memory MFA challenge generation and verification."""

    def __init__(self, default_ttl: float = 300.0) -> None:
        self.default_ttl = default_ttl
        self._challenges: dict[str, MFAChallenge] = {}

    def create_challenge(
        self,
        subject: str,
        method: str = "totp",
        code: str | None = None,
        ttl: float | None = None,
        metadata: dict[str, str] | None = None,
        now: float | None = None,
    ) -> MFAChallenge:
        if not subject:
            raise VaultError("MFA subject is required")
        current = _now(now)
        lifetime = self.default_ttl if ttl is None else ttl
        challenge = MFAChallenge(
            challenge_id=generate_id("mfa", 18),
            subject=subject,
            method=method,
            code=code or f"{secure_random_int(0, 999999):06d}",
            created_at=current,
            expires_at=current + lifetime,
            metadata=dict(metadata or {}),
        )
        self._challenges[challenge.challenge_id] = challenge
        return challenge

    def verify(self, challenge_id: str, code: str, now: float | None = None) -> MFAChallenge:
        challenge = self._challenges.get(challenge_id)
        if challenge is None:
            raise AuthenticationError("MFA challenge not found")
        if challenge.is_expired(now):
            raise AuthenticationError("MFA challenge expired")

        challenge.attempts += 1
        expected = challenge.code.encode()
        candidate = str(code).encode()
        if not constant_time_compare(candidate, expected):
            raise AuthenticationError("invalid MFA code")

        challenge.verified = True
        return challenge

    def get_challenge(self, challenge_id: str) -> MFAChallenge | None:
        return self._challenges.get(challenge_id)

    def list_challenges(self, subject: str | None = None) -> list[str]:
        challenges = self._challenges.values()
        if subject is not None:
            challenges = [challenge for challenge in challenges if challenge.subject == subject]
        return sorted(challenge.challenge_id for challenge in challenges)

    def tidy(self, now: float | None = None) -> int:
        to_remove = [
            challenge_id
            for challenge_id, challenge in self._challenges.items()
            if challenge.is_expired(now)
        ]
        for challenge_id in to_remove:
            self._challenges.pop(challenge_id, None)
        return len(to_remove)


@dataclass
class AuthEvent:
    """Authentication event log entry."""

    event_id: str
    backend: str
    subject: str
    success: bool
    reason: str = ""
    timestamp: float = field(default_factory=time.time)
    metadata: dict[str, str] = field(default_factory=dict)

    def to_dict(self) -> dict[str, Any]:
        return {
            "event_id": self.event_id,
            "backend": self.backend,
            "subject": self.subject,
            "success": self.success,
            "reason": self.reason,
            "timestamp": self.timestamp,
            "metadata": dict(self.metadata),
        }


class AuthEventLog:
    """Bounded in-memory auth event log."""

    def __init__(self, max_entries: int = 10000) -> None:
        self._max_entries = max_entries
        self._events: list[AuthEvent] = []

    def log(
        self,
        backend: str,
        subject: str,
        success: bool,
        reason: str = "",
        metadata: dict[str, str] | None = None,
        now: float | None = None,
    ) -> AuthEvent:
        event = AuthEvent(
            event_id=generate_id("auth", 18),
            backend=backend,
            subject=subject,
            success=success,
            reason=reason,
            timestamp=_now(now),
            metadata=dict(metadata or {}),
        )
        if len(self._events) >= self._max_entries:
            self._events.pop(0)
        self._events.append(event)
        return event

    def list_events(
        self,
        backend: str | None = None,
        subject: str | None = None,
        success: bool | None = None,
        since: float = 0.0,
    ) -> list[AuthEvent]:
        events = self._events
        if backend is not None:
            events = [event for event in events if event.backend == backend]
        if subject is not None:
            events = [event for event in events if event.subject == subject]
        if success is not None:
            events = [event for event in events if event.success is success]
        if since:
            events = [event for event in events if event.timestamp >= since]
        return list(events)

    @property
    def total_events(self) -> int:
        return len(self._events)

    def clear(self) -> None:
        self._events.clear()


@dataclass
class AuthConfigValidation:
    """Result from auth configuration validation."""

    valid: bool
    errors: list[str] = field(default_factory=list)
    warnings: list[str] = field(default_factory=list)

    def to_dict(self) -> dict[str, Any]:
        return {
            "valid": self.valid,
            "errors": list(self.errors),
            "warnings": list(self.warnings),
        }


def validate_auth_config(
    config: dict[str, Any],
    allowed_backend_types: set[str] | None = None,
) -> AuthConfigValidation:
    """Validate a lightweight auth configuration dictionary."""

    allowed = allowed_backend_types or {"userpass", "approle", "cert", "token"}
    errors: list[str] = []
    warnings: list[str] = []

    if not isinstance(config, dict):
        return AuthConfigValidation(valid=False, errors=["config must be a dictionary"])

    backends = config.get("backends")
    if not isinstance(backends, dict) or not backends:
        errors.append("backends must be a non-empty dictionary")
        return AuthConfigValidation(valid=False, errors=errors)

    for name, backend_config in backends.items():
        if not isinstance(name, str) or not name:
            errors.append("backend names must be non-empty strings")
            continue
        if not isinstance(backend_config, dict):
            errors.append(f"backend {name} must be a dictionary")
            continue

        backend_type = backend_config.get("type")
        if backend_type not in allowed:
            errors.append(f"backend {name} has unsupported type: {backend_type}")

        enabled = backend_config.get("enabled", True)
        if not isinstance(enabled, bool):
            errors.append(f"backend {name} enabled must be a boolean")

        default_ttl = backend_config.get("default_ttl")
        if default_ttl is not None and (
            not isinstance(default_ttl, int | float) or default_ttl < 0
        ):
            errors.append(f"backend {name} default_ttl must be a non-negative number")

        max_ttl = backend_config.get("max_ttl")
        if max_ttl is not None and (not isinstance(max_ttl, int | float) or max_ttl < 0):
            errors.append(f"backend {name} max_ttl must be a non-negative number")
        if isinstance(default_ttl, int | float) and isinstance(max_ttl, int | float):
            if max_ttl and default_ttl > max_ttl:
                warnings.append(f"backend {name} default_ttl exceeds max_ttl")

    return AuthConfigValidation(valid=not errors, errors=errors, warnings=warnings)


